// src/pages/KhaiBaoCoSo.js
import React, { useState, useCallback, useEffect } from 'react';
import axios from 'axios';
import * as XLSX from 'xlsx'; // Import thư viện xlsx (vẫn dùng để đọc CSV)
import './KhaiBaoCoSo.css'; // Import file CSS
import speciesOptions from '../data/speciesData'; // Import danh sách loài từ file mới (nếu có)
import { jwtDecode } from 'jwt-decode'; // Import jwt-decode

function KhaiBaoCoSo() {
  // Initial form state for resetting
  const initialFormState = {
    // Thông tin cơ sở
    tenCoSo: '', tinhThanhPho: '', xaPhuong: '', diaChiCoSo: '', vido: '', kinhdo: '',
    loaiHinhCoSo: '', ngayThanhLap: '', giayPhepKinhDoanh: '',

    // Người đại diện
    tenNguoiDaiDien: '', namSinh: '', soCCCD: '', ngayCapCCCD: '', noiCapCCCD: '',
    soDienThoaiNguoiDaiDien: '', diaChiNguoiDaiDien: '', emailNguoiDaiDien: '',

    // Cơ sở gây nuôi
    mucDichNuoi: '', hinhThucNuoi: '', maSoCoSoGayNuoi: '', tongDan: '',

    // Cơ sở kinh doanh, chế biến gỗ
    loaiHinhKinhDoanhGo: '', nganhNgheKinhDoanhGo: '', khoiLuong: '',

    // Loại cơ sở đăng ký (quan trọng cho cả 2 loại)
    loaiCoSoDangKy: '', // Thêm trường này vào initial state

    // Thông tin lâm sản (cho cả 2 loại)
    tenLamSan: '', tenKhoaHoc: '',

    // Thông tin giấy phép (cho cả 2 loại)
    issueDate: '', expiryDate: '',

    // Trạng thái
    trangThai: 'Hoạt động', // Giá trị mặc định
    ghiChu: '',
  };

  const [formData, setFormData] = useState(initialFormState);
  const [message, setMessage] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const [excelData, setExcelData] = useState([]); // State để lưu dữ liệu từ Excel/CSV
  const [csvFile, setCsvFile] = useState(null); // State để lưu trữ file CSV đã chọn

  // Ánh xạ các header từ CSV/Excel sang tên trường trong MongoDB
  const headerMap = {
    'Tên cơ sở': 'tenCoSo',
    'Tỉnh (Thành phố)': 'tinhThanhPho',
    'Xã (Phường)': 'xaPhuong',
    'Địa chỉ': 'diaChiCoSo',
    'Vĩ độ': 'vido',
    'Kinh độ': 'kinhdo',
    'Ngày thành lập': 'ngayThanhLap',
    'Số giấy phép kinh doanh': 'giayPhepKinhDoanh',
    'Họ và tên người đại diện': 'tenNguoiDaiDien',
    'Năm sinh': 'namSinh',
    'Số CCCD/Hộ chiếu': 'soCCCD',
    'Ngày cấp CCCD': 'ngayCapCCCD',
    'Nơi cấp CCCD': 'noiCapCCCD',
    'Số điện thoại người đại diện': 'soDienThoaiNguoiDaiDien',
    'Địa chỉ người đại diện': 'diaChiNguoiDaiDien',
    'Mục đích nuôi': 'mucDichNuoi',
    'Hình thức nuôi': 'hinhThucNuoi',
    'Mã số cơ sở gây nuôi': 'maSoCoSoGayNuoi',
    'Tổng đàn': 'tongDan',
    'Loại hình kinh doanh gỗ': 'loaiHinhKinhDoanhGo',
    'Ngành nghề kinh doanh gỗ': 'nganhNgheKinhDoanhGo',
    'Khối lượng': 'khoiLuong',
    'Tên lâm sản': 'tenLamSan',
    'Tên khoa học': 'tenKhoaHoc',
    'Trạng thái': 'trangThai',
    'Ghi chú': 'ghiChu',
    'Ngày cấp (License)': 'issueDate',
    'Ngày hết hạn (License)': 'expiryDate',
    'loại cơ sở đăng ký': 'loaiCoSoDangKy', // Đảm bảo key này khớp với header trong CSV
  };

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (token) {
      try {
        const decodedToken = jwtDecode(token);
        if (decodedToken.role === 'admin') {
          setIsAdmin(true);
        }
      } catch (err) {
        console.error('Lỗi giải mã token:', err);
        // Xử lý lỗi giải mã token (ví dụ: token hết hạn hoặc không hợp lệ)
      }
    }
  }, []);

  const handleChange = useCallback((e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsLoading(true);
    setMessage('');
    setError('');

    const token = localStorage.getItem('token');
    if (!token) {
      setError('Bạn cần đăng nhập để thực hiện chức năng này.');
      setIsLoading(false);
      return;
    }

    try {
      const config = {
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        }
      };
      const response = await axios.post('http://localhost:10000/api/farms', formData, config);
      setMessage(response.data.message);
      setFormData(initialFormState); // Reset form
    } catch (err) {
      console.error('Lỗi khi gửi dữ liệu:', err);
      setError(err.response?.data?.message || 'Đã xảy ra lỗi khi tạo cơ sở.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleFileUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      setCsvFile(file); // Lưu file đã chọn
      const reader = new FileReader();
      reader.onload = (event) => {
        const binaryStr = event.target.result;
        const workbook = XLSX.read(binaryStr, { type: 'binary' });
        const sheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[sheetName];

        // Đọc dữ liệu từ sheet, lấy hàng đầu tiên làm headers
        const rows = XLSX.utils.sheet_to_json(worksheet, { header: 1 });
        if (rows.length === 0) {
          setError('File CSV không có dữ liệu.');
          setExcelData([]);
          return;
        }

        const headers = rows[0]; // Hàng đầu tiên là headers
        const dataRows = rows.slice(1); // Các hàng còn lại là dữ liệu

        const processedData = dataRows.map(row => {
          const mappedData = {};
          headers.forEach((header, index) => {
            // Chuẩn hóa header từ CSV để khớp với headerMap
            const normalizedHeader = header ? header.toString().trim() : '';
            const mappedKey = headerMap[normalizedHeader];

            if (mappedKey) {
              // Gán giá trị vào mappedData
              mappedData[mappedKey] = row[index];
            }
          });
          return mappedData;
        });

        console.log("Dữ liệu đã được xử lý từ CSV:", processedData); // LOG DỮ LIỆU ĐÃ XỬ LÝ
        setExcelData(processedData);
        setMessage(`Đã đọc được ${processedData.length} dòng dữ liệu từ CSV.`);
        setError(''); // Clear any previous errors
      };
      reader.readAsBinaryString(file);
    }
  };

  const handleBulkSubmit = async () => {
    if (excelData.length === 0) {
      setError('Không có dữ liệu để tải lên hàng loạt.');
      return;
    }

    setIsLoading(true);
    setMessage('');
    setError('');

    const token = localStorage.getItem('token');
    if (!token) {
      setError('Bạn cần đăng nhập để thực hiện chức năng này.');
      setIsLoading(false);
      return;
    }

    try {
      const config = {
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        }
      };
      console.log("Dữ liệu gửi đi (Bulk Upload):", excelData); // LOG DỮ LIỆU TRƯỚC KHI GỬI
      const response = await axios.post('http://localhost:10000/api/farms/bulk', excelData, config);
      setMessage(response.data.message);
      if (response.data.errors && response.data.errors.length > 0) {
        setError(`Có lỗi xảy ra với một số cơ sở: ${response.data.errors.map(e => e.message).join(', ')}`);
      }
      setExcelData([]); // Clear data after successful upload
      setCsvFile(null); // Clear selected file
    } catch (err) {
      console.error('Lỗi khi tải lên hàng loạt:', err);
      setError(err.response?.data?.message || 'Đã xảy ra lỗi khi tải lên hàng loạt.');
      if (err.response?.data?.errors) {
        // Display specific errors from backend if available
        setError(prev => prev + ' Chi tiết lỗi: ' + err.response.data.errors.map(e => `${e.index}: ${e.message}`).join('; '));
      }
    } finally {
      setIsLoading(false);
    }
  };

  const resetCsvUpload = () => {
    setCsvFile(null);
    setExcelData([]);
    setMessage('');
    setError('');
  };

  return (
    <div className="khai-bao-co-so-container">
      <h1>Khai Báo Cơ Sở</h1>

      {message && <div className="message success-message">{message}</div>}
      {error && <div className="message error-message">{error}</div>}

      <form onSubmit={handleSubmit} className="khai-bao-form">
        <section className="khai-bao-section">
          <h2>Thông tin cơ sở</h2>
          <div className="form-group">
            <label htmlFor="tenCoSo">Tên cơ sở:</label>
            <input type="text" id="tenCoSo" name="tenCoSo" value={formData.tenCoSo} onChange={handleChange} required />
          </div>
          <div className="form-group">
            <label htmlFor="tinhThanhPho">Tỉnh (Thành phố):</label>
            <input type="text" id="tinhThanhPho" name="tinhThanhPho" value={formData.tinhThanhPho} onChange={handleChange} required />
          </div>
          <div className="form-group">
            <label htmlFor="xaPhuong">Xã (Phường):</label>
            <input type="text" id="xaPhuong" name="xaPhuong" value={formData.xaPhuong} onChange={handleChange} required />
          </div>
          <div className="form-group">
            <label htmlFor="diaChiCoSo">Địa chỉ cơ sở:</label>
            <input type="text" id="diaChiCoSo" name="diaChiCoSo" value={formData.diaChiCoSo} onChange={handleChange} required />
          </div>
          <div className="form-group">
            <label htmlFor="vido">Vĩ độ:</label>
            <input type="text" id="vido" name="vido" value={formData.vido} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="kinhdo">Kinh độ:</label>
            <input type="text" id="kinhdo" name="kinhdo" value={formData.kinhdo} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="ngayThanhLap">Ngày thành lập:</label>
            <input type="date" id="ngayThanhLap" name="ngayThanhLap" value={formData.ngayThanhLap} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="giayPhepKinhDoanh">Số giấy phép kinh doanh:</label>
            <input type="text" id="giayPhepKinhDoanh" name="giayPhepKinhDoanh" value={formData.giayPhepKinhDoanh} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="trangThai">Trạng thái:</label>
            <select id="trangThai" name="trangThai" value={formData.trangThai} onChange={handleChange}>
              <option value="Hoạt động">Hoạt động</option>
              <option value="Tạm dừng">Tạm dừng</option>
              <option value="Đình chỉ">Đình chỉ</option>
            </select>
          </div>
          <div className="form-group">
            <label htmlFor="ghiChu">Ghi chú:</label>
            <textarea id="ghiChu" name="ghiChu" value={formData.ghiChu} onChange={handleChange}></textarea>
          </div>
        </section>

        <section className="khai-bao-section">
          <h2>Thông tin người đại diện</h2>
          <div className="form-group">
            <label htmlFor="tenNguoiDaiDien">Họ và tên người đại diện:</label>
            <input type="text" id="tenNguoiDaiDien" name="tenNguoiDaiDien" value={formData.tenNguoiDaiDien} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="namSinh">Năm sinh:</label>
            <input type="number" id="namSinh" name="namSinh" value={formData.namSinh} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="soCCCD">Số CCCD/Hộ chiếu:</label>
            <input type="text" id="soCCCD" name="soCCCD" value={formData.soCCCD} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="ngayCapCCCD">Ngày cấp CCCD:</label>
            <input type="date" id="ngayCapCCCD" name="ngayCapCCCD" value={formData.ngayCapCCCD} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="noiCapCCCD">Nơi cấp CCCD:</label>
            <input type="text" id="noiCapCCCD" name="noiCapCCCD" value={formData.noiCapCCCD} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="soDienThoaiNguoiDaiDien">Số điện thoại người đại diện:</label>
            <input type="tel" id="soDienThoaiNguoiDaiDien" name="soDienThoaiNguoiDaiDien" value={formData.soDienThoaiNguoiDaiDien} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="diaChiNguoiDaiDien">Địa chỉ người đại diện:</label>
            <input type="text" id="diaChiNguoiDaiDien" name="diaChiNguoiDaiDien" value={formData.diaChiNguoiDaiDien} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="emailNguoiDaiDien">Email người đại diện:</label>
            <input type="email" id="emailNguoiDaiDien" name="emailNguoiDaiDien" value={formData.emailNguoiDaiDien} onChange={handleChange} />
          </div>
        </section>

        <section className="khai-bao-section">
          <h2>Loại hình cơ sở đăng ký</h2>
          <div className="form-group">
            <label htmlFor="loaiCoSoDangKy">Chọn loại cơ sở:</label>
            <select
              id="loaiCoSoDangKy"
              name="loaiCoSoDangKy"
              value={formData.loaiCoSoDangKy}
              onChange={handleChange}
              required
            >
              <option value="">-- Chọn loại cơ sở --</option>
              <option value="Đăng ký cơ sở gây nuôi">Đăng ký cơ sở gây nuôi</option>
              <option value="Đăng ký cơ sở kinh doanh, chế biến gỗ">Đăng ký cơ sở kinh doanh, chế biến gỗ</option>
            </select>
          </div>

          {formData.loaiCoSoDangKy === 'Đăng ký cơ sở gây nuôi' && (
            <>
              <h3>Thông tin cơ sở gây nuôi</h3>
              <div className="form-group">
                <label htmlFor="mucDichNuoi">Mục đích nuôi:</label>
                <input type="text" id="mucDichNuoi" name="mucDichNuoi" value={formData.mucDichNuoi} onChange={handleChange} />
              </div>
              <div className="form-group">
                <label htmlFor="hinhThucNuoi">Hình thức nuôi:</label>
                <input type="text" id="hinhThucNuoi" name="hinhThucNuoi" value={formData.hinhThucNuoi} onChange={handleChange} />
              </div>
              <div className="form-group">
                <label htmlFor="maSoCoSoGayNuoi">Mã số cơ sở gây nuôi:</label>
                <input type="text" id="maSoCoSoGayNuoi" name="maSoCoSoGayNuoi" value={formData.maSoCoSoGayNuoi} onChange={handleChange} />
              </div>
              <div className="form-group">
                <label htmlFor="tongDan">Tổng đàn:</label>
                <input type="number" id="tongDan" name="tongDan" value={formData.tongDan} onChange={handleChange} />
              </div>
              <div className="form-group">
                <label htmlFor="tenLamSanNuoi">Tên lâm sản (nuôi):</label>
                <select id="tenLamSanNuoi" name="tenLamSan" value={formData.tenLamSan} onChange={handleChange}>
                  <option value="">-- Chọn lâm sản --</option>
                  {speciesOptions.map((species, index) => (
                    <option key={index} value={species.name}>{species.name}</option>
                  ))}
                </select>
              </div>
              <div className="form-group">
                <label htmlFor="tenKhoaHocNuoi">Tên khoa học (nuôi):</label>
                <input type="text" id="tenKhoaHocNuoi" name="tenKhoaHoc" value={formData.tenKhoaHoc} onChange={handleChange} readOnly />
              </div>
            </>
          )}

          {formData.loaiCoSoDangKy === 'Đăng ký cơ sở kinh doanh, chế biến gỗ' && (
            <>
              <h3>Thông tin cơ sở kinh doanh, chế biến gỗ</h3>
              <div className="form-group">
                <label htmlFor="loaiHinhKinhDoanhGo">Loại hình kinh doanh gỗ:</label>
                <input type="text" id="loaiHinhKinhDoanhGo" name="loaiHinhKinhDoanhGo" value={formData.loaiHinhKinhDoanhGo} onChange={handleChange} />
              </div>
              <div className="form-group">
                <label htmlFor="nganhNgheKinhDoanhGo">Ngành nghề kinh doanh gỗ:</label>
                <input type="text" id="nganhNgheKinhDoanhGo" name="nganhNgheKinhDoanhGo" value={formData.nganhNgheKinhDoanhGo} onChange={handleChange} />
              </div>
              <div className="form-group">
                <label htmlFor="khoiLuong">Khối lượng:</label>
                <input type="number" id="khoiLuong" name="khoiLuong" value={formData.khoiLuong} onChange={handleChange} />
              </div>
              <div className="form-group">
                <label htmlFor="tenLamSanGo">Tên lâm sản (gỗ):</label>
                <select id="tenLamSanGo" name="tenLamSan" value={formData.tenLamSan} onChange={handleChange}>
                  <option value="">-- Chọn lâm sản --</option>
                  {speciesOptions.map((species, index) => (
                    <option key={index} value={species.name}>{species.name}</option>
                  ))}
                </select>
              </div>
              <div className="form-group">
                <label htmlFor="tenKhoaHocGo">Tên khoa học (gỗ):</label>
                <input type="text" id="tenKhoaHocGo" name="tenKhoaHoc" value={formData.tenKhoaHoc} onChange={handleChange} readOnly />
              </div>
            </>
          )}

          {(formData.loaiCoSoDangKy === 'Đăng ký cơ sở gây nuôi' || formData.loaiCoSoDangKy === 'Đăng ký cơ sở kinh doanh, chế biến gỗ') && (
            <>
              <h3>Thông tin giấy phép</h3>
              <div className="form-group">
                <label htmlFor="issueDate">Ngày cấp (License):</label>
                <input type="date" id="issueDate" name="issueDate" value={formData.issueDate} onChange={handleChange} />
              </div>
              <div className="form-group">
                <label htmlFor="expiryDate">Ngày hết hạn (License):</label>
                <input type="date" id="expiryDate" name="expiryDate" value={formData.expiryDate} onChange={handleChange} />
              </div>
            </>
          )}
        </section>

        <button type="submit" className="submit-button" disabled={isLoading}>
          {isLoading ? 'Đang gửi...' : 'Khai báo cơ sở'}
        </button>
      </form>

      {isAdmin && <hr className="section-divider" />}

      {isAdmin && (
        <section className="khai-bao-section excel-upload-section">
          <h2>Tải lên dữ liệu hàng loạt từ CSV</h2>
          <div className="file-upload-group">
            <label htmlFor="csvUpload" className="file-upload-label">
              Chọn file CSV (.csv):
            </label>
            <input
              type="file"
              id="csvUpload"
              accept=".csv"
              onChange={handleFileUpload}
              className="file-input"
            />
            {csvFile && <span className="file-name">{csvFile.name}</span>}
          </div>
          {excelData.length > 0 && (
            <div className="excel-preview-info">
              <p>Đã đọc được {excelData.length} dòng dữ liệu từ CSV. Vui lòng nhấn "Tải lên hàng loạt" để lưu.</p>
              <button
                onClick={handleBulkSubmit}
                className="submit-button bulk-upload-button"
                disabled={isLoading}
              >
                {isLoading ? 'Đang tải...' : `Tải lên hàng loạt (${excelData.length} cơ sở)`}
              </button>
              <button
                onClick={resetCsvUpload}
                className="clear-excel-button"
                disabled={isLoading}
              >
                Xóa dữ liệu CSV
              </button>
            </div>
          )}
        </section>
      )}
    </div>
  );
}

export default KhaiBaoCoSo;
